
using LearnPath.API.Common; using LearnPath.API.DTOs.Certificate; using LearnPath.API.Data; using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Mvc; using Microsoft.EntityFrameworkCore; using System.Security.Claims; namespace LearnPath.API.Controllers; [ApiController] [Route("api/v1/certificates")] [Authorize] public class CertificateController : ControllerBase { private readonly ApplicationDbContext _context; public CertificateController(ApplicationDbContext context) => _context = context; private string UserId => User.FindFirstValue(ClaimTypes.NameIdentifier)!; [HttpGet] public async Task<IActionResult> GetMyCertificates() { var certs = await _context.Certificates .Where(c => c.UserId == UserId) .Include(c => c.LearningPath) .OrderByDescending(c => c.IssuedAt) .Select(c => new CertificateResponseDto { Id = c.Id, LearningPathId = c.LearningPathId, LearningPathTitle = c.LearningPath.Title, CertificateUrl = c.CertificateUrl, IssuedAt = c.IssuedAt, }) .ToListAsync(); return Ok(ApiResponse<List<CertificateResponseDto>>.Ok(certs)); } }

